import re

expected_version = '1.0.11'
errors = []

pom = Path('pom.xml').read_text(encoding='utf-8')
plugin = Path('src/main/resources/plugin.yml').read_text(encoding='utf-8')
changelog = Path(f'CHANGELOG_{expected_version}.md')
forum = Path('论坛介绍_LISeasons插件.md').read_text(encoding='utf-8')
festival_type = Path('src/main/java/com/liseasons/festival/FestivalType.java').read_text(encoding='utf-8')
festivals = Path('src/main/resources/festivals.yml').read_text(encoding='utf-8')

if f'<version>{expected_version}</version>' not in pom:
    errors.append('pom.xml version mismatch')
if f'version: {expected_version}' not in plugin:
    errors.append('plugin.yml version mismatch')
if not changelog.exists():
    errors.append('missing changelog')
else:
    text = changelog.read_text(encoding='utf-8')
    for term in ['New Year', "Valentine's Day", 'Easter', 'Halloween', 'Christmas']:
        if term not in text:
            errors.append(f'changelog missing {term}')
if f'当前版本**：{expected_version}' not in forum and f'当前版本**：{expected_version}' not in forum:
    errors.append('forum current version mismatch')
if f'### v{expected_version}' not in forum:
    errors.append('forum changelog missing new version')

constants = re.findall(r'^    ([A-Z_]+)\(', festival_type, flags=re.M)
expected_constants = ['NEW_YEAR', 'VALENTINES_DAY', 'EASTER', 'HALLOWEEN', 'CHRISTMAS']
if constants != expected_constants:
    errors.append(f'FestivalType constants mismatch: {constants}')

for forbidden in ['SPRING_FESTIVAL', 'SERVER_ANNIVERSARY', 'LABOR_DAY', 'CHILDRENS_DAY']:
    if forbidden in festival_type:
        errors.append(f'forbidden default festival remains in FestivalType: {forbidden}')

for key in ['new-year:', 'valentines:', 'easter:', 'halloween:', 'christmas:']:
    if key not in festivals:
        errors.append(f'festivals.yml missing {key}')

for forbidden in ['spring-festival:', 'server-anniversary:', 'labor-day:', 'childrens-day:']:
    if forbidden in festivals:
        errors.append(f'forbidden festival remains in festivals.yml: {forbidden}')

if errors:
    print('\n'.join(errors))
    raise SystemExit(1)
print('OK version=1.0.11; only 5 default festivals configured and documented')
