     private Map<Season, TemperatureRangeConfig> loadSeasonBaseRanges(FileConfiguration temperatureFile) {
         Map<Season, TemperatureRangeConfig> ranges = new EnumMap<>(Season.class);
         for (Season season : Season.values()) {
             String path = "base-temperature.season." + season.key();
             ranges.put(season, new TemperatureRangeConfig(
                     temperatureFile.getDouble(path + ".min", temperatureFile.getDouble("season-base-temperature." + season.key(), 18.0D)),
                     temperatureFile.getDouble(path + ".max", temperatureFile.getDouble("season-base-temperature." + season.key(), 18.0D))
             ));
         }
         return ranges;
     }

     private Map<String, Double> loadDoubleSection(FileConfiguration file, String path) {
         Map<String, Double> values = new LinkedHashMap<>();
         ConfigurationSection section = file.getConfigurationSection(path);
         if (section == null) {
             return values;
         }
         for (String key : section.getKeys(false)) {
             if (section.isConfigurationSection(key)) {
                 continue;
             }
             values.put(key.toLowerCase(), section.getDouble(key));
         }
         return values;
     }

     private SeasonBiomeColorConfig loadBiomeColorConfig() {
         File file = new File(this.plugin.getDataFolder(), "season-color.yml");
         FileConfiguration colorFile = YamlConfiguration.loadConfiguration(file);

         boolean enabled = colorFile.getBoolean("enable", true);
         long intervalTicks = colorFile.getLong("interval-ticks", 60L);
         int radius = colorFile.getInt("radius", 8);

         Map<Season, Map<NamespacedKey, NamespacedKey>> allMappings = new EnumMap<>(Season.class);
         ConfigurationSection seasonsSection = colorFile.getConfigurationSection("seasons");
         if (seasonsSection != null) {
             for (String seasonKey : seasonsSection.getKeys(false)) {
                 Season season = Season.fromKey(seasonKey).orElse(null);
                 if (season == null) {
                     this.plugin.getLogger().warning("未知季节键名，跳过: " + seasonKey);
                     continue;
                 }
                 ConfigurationSection biomeSection = seasonsSection.getConfigurationSection(seasonKey);
                 if (biomeSection == null) {
                     continue;
                 }
                 Map<NamespacedKey, NamespacedKey> mappings = new LinkedHashMap<>();
                 for (String biomeKey : biomeSection.getKeys(false)) {
                     String targetKey = biomeSection.getString(biomeKey);
                     if (targetKey == null || targetKey.isBlank()) {
                         continue;
                     }
                     NamespacedKey original = parseNamespacedKey(biomeKey);
                     NamespacedKey target = parseNamespacedKey(targetKey);
                     if (original != null && target != null) {
                         mappings.put(original, target);
                     }
                 }
                 allMappings.put(season, Collections.unmodifiableMap(mappings));
             }
         }

         Map<Season, Map<NamespacedKey, BiomeVisualColors>> allVisuals = loadBiomeVisuals(colorFile);
         Map<Season, NamespacedKey> spoofTargets = new EnumMap<>(Season.class);
         ConfigurationSection spoofSeasonSection = colorFile.getConfigurationSection("biome-spoof.seasons");
         if (spoofSeasonSection != null) {
             for (String seasonKey : spoofSeasonSection.getKeys(false)) {
                 Season season = Season.fromKey(normalizeSeasonKey(seasonKey)).orElse(null);
                 NamespacedKey target = parseNamespacedKey(spoofSeasonSection.getString(seasonKey));
                 if (season != null && target != null) {
                     spoofTargets.put(season, target);
                 }
             }
         }
         putDefaultSpoofTargets(spoofTargets);
         return new SeasonBiomeColorConfig(
                 enabled,
                 intervalTicks,
                 radius,
                 allMappings,
                 allVisuals,
                 colorFile.getBoolean("biome-spoof.enable", true),
                 colorFile.getInt("biome-spoof.radius-chunks", 8),
                 colorFile.getInt("biome-spoof.budget-chunks-per-tick", 8),
                 colorFile.getInt("biome-spoof.step-xz", 4),
                 colorFile.getInt("biome-spoof.step-y", 4),
                 spoofTargets
         );
     }

     private void putDefaultSpoofTargets(Map<Season, NamespacedKey> spoofTargets) {
         spoofTargets.putIfAbsent(Season.SPRING, NamespacedKey.minecraft("flower_forest"));
         spoofTargets.putIfAbsent(Season.SUMMER, NamespacedKey.minecraft("plains"));
         spoofTargets.putIfAbsent(Season.AUTUMN, NamespacedKey.minecraft("windswept_savanna"));
         spoofTargets.putIfAbsent(Season.WINTER, NamespacedKey.minecraft("snowy_plains"));
     }

     private Map<Season, Map<NamespacedKey, BiomeVisualColors>> loadBiomeVisuals(FileConfiguration colorFile) {
         Map<Season, Map<NamespacedKey, BiomeVisualColors>> allVisuals = new EnumMap<>(Season.class);
         ConfigurationSection groupsSection = colorFile.getConfigurationSection("biome-visuals");
         if (groupsSection == null) {
             return allVisuals;
         }

         for (String groupKey : groupsSection.getKeys(false)) {
             ConfigurationSection groupSection = groupsSection.getConfigurationSection(groupKey);
             if (groupSection == null) {
                 continue;
             }
             List<NamespacedKey> biomes = groupSection.getStringList("biomes").stream()
                     .map(this::parseNamespacedKey)
                     .filter(java.util.Objects::nonNull)
                     .toList();
             ConfigurationSection seasonsSection = groupSection.getConfigurationSection("seasons");
             if (biomes.isEmpty() || seasonsSection == null) {
                 continue;
             }
             for (String seasonKey : seasonsSection.getKeys(false)) {
                 Season season = Season.fromKey(normalizeSeasonKey(seasonKey)).orElse(null);
                 ConfigurationSection seasonSection = seasonsSection.getConfigurationSection(seasonKey);
                 if (season == null || seasonSection == null) {
                     continue;
                 }
                 BiomeVisualColors colors = new BiomeVisualColors(
                         parseHexColor(seasonSection.getString("sky")),
                         parseHexColor(seasonSection.getString("water")),
                         parseHexColor(seasonSection.getString("waterFog")),
                         parseHexColor(seasonSection.getString("grass")),
                         parseHexColor(seasonSection.getString("tree")),
                         parseHexColor(seasonSection.getString("fog"))
                 );
                 if (!colors.hasAnyColor()) {
                     continue;
                 }
                 Map<NamespacedKey, BiomeVisualColors> seasonVisuals = allVisuals.computeIfAbsent(season, ignored -> new LinkedHashMap<>());
                 for (NamespacedKey biome : biomes) {
                     seasonVisuals.put(biome, colors);
                 }
             }
         }
         return allVisuals;
     }

     private String normalizeSeasonKey(String seasonKey) {
         return "fall".equalsIgnoreCase(seasonKey) ? "autumn" : seasonKey;
     }

     private Integer parseHexColor(String raw) {
         if (raw == null || raw.isBlank()) {
             return null;
         }
         String normalized = raw.trim();
         if (normalized.startsWith("#")) {
             normalized = normalized.substring(1);
         }
         if (normalized.length() != 6) {
             this.plugin.getLogger().warning("无法解析颜色配置: " + raw + "，请使用 6 位 HEX，例如 FFFFFF");
             return null;
         }
         try {
             return Integer.parseInt(normalized, 16);
         } catch (NumberFormatException ex) {
             this.plugin.getLogger().warning("无法解析颜色配置: " + raw + "，请使用 0-9 或 A-F");
             return null;
         }
     }

     private NamespacedKey parseNamespacedKey(String raw) {
         if (raw == null || raw.isBlank()) {
             return null;
         }
         String normalized = raw.toLowerCase(java.util.Locale.ROOT);
         return normalized.contains(":") ? NamespacedKey.fromString(normalized) : NamespacedKey.minecraft(normalized);
     }

     private MonthDay parseMonthDay(String raw, MonthDay fallback) {
         if (raw == null || raw.isBlank()) {
             return fallback;
         }

         try {
             String[] split = raw.split("-");
             if (split.length != 2) {
                 return fallback;
             }
             int month = Integer.parseInt(split[0]);
             int day = Integer.parseInt(split[1]);
             return MonthDay.of(month, day);
         } catch (DateTimeParseException | IllegalArgumentException ex) {
             this.plugin.getLogger().warning("无法解析节气日期配置: " + raw + "，将使用默认值 " + fallback);
             return fallback;
         }
     }

