                             MessageManager.Placeholder.of("current", term == state.solarTerm() ? "当前节气" : "尚未到来")
                     )
             ), slot++);
         }
         fill(inventory, createInfoItem(
                 Material.COMPASS,
                 messages.rawMessage("calendar.month-summary-item"),
