     private void renderSeasonFrame(Inventory inventory, Season season) {
         Material plank = seasonalPlank(season);
         Material crop = seasonalCrop(season);
         Material accent = seasonalAccent(season);
         Component blank = Component.text(" ");
 
         int[] woodenFrame = {
                 0, 1, 2, 3, 5, 6, 7, 8,
                 9, 17, 18, 26, 27, 35, 36, 44, 47, 53
         };
         for (int slot : woodenFrame) {
             if (inventory.getItem(slot) == null) {
                 fill(inventory, createSimpleItem(plank, blank), slot);
             }
         }
 
         int[] cropCorners = {0, 8, 36, 44};
         for (int slot : cropCorners) {
             if (inventory.getItem(slot) == null || inventory.getItem(slot).getType() == plank) {
                 fill(inventory, createSimpleItem(crop, blank), slot);
             }
         }
 
         int[] accentSlots = {10, 11, 12, 14, 15, 16, 28, 29, 30, 32, 33, 34};
         for (int slot : accentSlots) {
             if (inventory.getItem(slot) == null) {
                 fill(inventory, createSimpleItem(accent, blank), slot);
             }
         }
     }
 
