    private List<String> loadLayout(FileConfiguration guiFile) {
        List<String> layout = guiFile.getStringList("calendar.layout");
        if (layout.isEmpty()) {
            return List.of();
        }
        return layout.stream()
                .limit(6)
                .map(row -> row == null ? "" : row)
                .toList();
    }

    private Map<String, CalendarConfig.LayoutIconConfig> loadLayoutIcons(FileConfiguration guiFile) {
        Map<String, CalendarConfig.LayoutIconConfig> icons = new LinkedHashMap<>();
        ConfigurationSection section = guiFile.getConfigurationSection("calendar.icons");
        if (section == null) {
            return icons;
        }
        for (String key : section.getKeys(false)) {
            if (key == null || key.isBlank()) {
                continue;
            }
            String path = "calendar.icons." + key;
            CalendarConfig.GuiItemConfig item = loadGuiItem(
                    guiFile,
                    path,
                    guiFile.getBoolean(path + ".enabled", true),
                    -1,
                    loadMaterial(guiFile.getString(path + ".material"), Material.PAPER),
                    loadOptionalMaterial(guiFile.getString(path + ".active-material"), null),
                    loadOptionalMaterial(guiFile.getString(path + ".cold-material"), null),
                    loadOptionalMaterial(guiFile.getString(path + ".hot-material"), null),
                    guiFile.getString(path + ".name", " "),
                    stringList(guiFile, path + ".lore", List.of())
            );
            icons.put(key, new CalendarConfig.LayoutIconConfig(
                    item.enabled(),
                    item.material(),
                    item.activeMaterial(),
                    item.coldMaterial(),
                    item.hotMaterial(),
                    guiFile.getString(path + ".type", "item").trim().toLowerCase(java.util.Locale.ROOT),
                    parseSeason(guiFile.getString(path + ".season")),
                    parseCalendarPage(guiFile.getString(path + ".page")),
                    item
            ));
        }
        return icons;
    }

    private Season parseSeason(String raw) {
        if (raw == null || raw.isBlank()) {
            return null;
        }
        try {
            return Season.valueOf(raw.trim().toUpperCase(java.util.Locale.ROOT));
        } catch (IllegalArgumentException ex) {
            this.plugin.getLogger().warning("Invalid gui.yml season '" + raw + "'");
            return null;
        }
    }

    private CalendarPage parseCalendarPage(String raw) {
        if (raw == null || raw.isBlank()) {
            return null;
        }
        String normalized = raw.trim().replace('-', '_').toUpperCase(java.util.Locale.ROOT);
        try {
            return CalendarPage.valueOf(normalized);
        } catch (IllegalArgumentException ex) {
            this.plugin.getLogger().warning("Invalid gui.yml page '" + raw + "'");
            return null;
        }
    }

