    private int layoutSlot(CalendarConfig config, char key) {
        if (config.layout() == null || config.layout().isEmpty()) {
            return -1;
        }
        for (int row = 0; row < config.layout().size(); row++) {
            String line = config.layout().get(row);
            int column = line.indexOf(key);
            if (column >= 0 && column < 9) {
                return row * 9 + column;
            }
        }
        return -1;
    }

    private CalendarPage layoutPageAt(CalendarConfig config, int slot) {
        if (config.layout() == null || config.layout().isEmpty() || slot < 0) {
            return null;
        }
        int row = slot / 9;
        int column = slot % 9;
        if (row >= config.layout().size()) {
            return null;
        }
        String line = config.layout().get(row);
        if (column >= line.length()) {
            return null;
        }
        CalendarConfig.LayoutIconConfig icon = config.icon(String.valueOf(line.charAt(column)));
        return icon == null ? null : icon.page();
    }
