     private Material loadMaterial(String raw, Material fallback) {
         Material material = loadOptionalMaterial(raw, fallback);
         return material == null ? fallback : material;
     }
 
     private Material loadOptionalMaterial(String raw, Material fallback) {
         if (raw == null || raw.isBlank()) {
             return fallback;
         }
         Material material = Material.matchMaterial(raw.trim());
         if (material == null) {
             this.plugin.getLogger().warning("Invalid gui.yml material '" + raw + "', fallback to " + (fallback == null ? "empty" : fallback.name()));
             return fallback;
         }
         return material;
     }
 
