     private List<String> loadLayout(FileConfiguration guiFile) {
         List<String> layout = guiFile.getStringList("calendar.layout");
         if (layout.isEmpty()) {
             return List.of();
         }
         return layout.stream()
                 .limit(6)
                 .map(row -> row == null ? "" : row)
                 .toList();
     }
 
