 public final class ConfigManager {
     private final LISeasonsPlugin plugin;
     private PluginConfig pluginConfig;
 
     public ConfigManager(LISeasonsPlugin plugin) {
         this.plugin = plugin;
         this.pluginConfig = load();
     }
 
     public PluginConfig reload() {
         this.plugin.reloadConfig();
         this.plugin.reloadMessagesConfig();
         this.pluginConfig = load();
         return this.pluginConfig;
     }
 
     public PluginConfig getConfig() {
         return this.pluginConfig;
     }
 
     private PluginConfig load() {
         Map<Season, Integer> seasonDurations = new EnumMap<>(Season.class);
         for (Season season : Season.values()) {
             int value = this.plugin.getConfig().getInt("time.season-duration-days." + season.key(), 24);
             seasonDurations.put(season, Math.max(1, value));
         }
 
         Map<Season, MonthDay> seasonStartDates = new EnumMap<>(Season.class);
         seasonStartDates.put(Season.SPRING, parseMonthDay(this.plugin.getConfig().getString("time.season-start-dates.spring"), MonthDay.of(3, 4)));
         seasonStartDates.put(Season.SUMMER, parseMonthDay(this.plugin.getConfig().getString("time.season-start-dates.summer"), MonthDay.of(6, 4)));
         seasonStartDates.put(Season.AUTUMN, parseMonthDay(this.plugin.getConfig().getString("time.season-start-dates.autumn"), MonthDay.of(9, 4)));
         seasonStartDates.put(Season.WINTER, parseMonthDay(this.plugin.getConfig().getString("time.season-start-dates.winter"), MonthDay.of(12, 4)));
 
         Map<SolarTerm, MonthDay> gregorianDates = new EnumMap<>(SolarTerm.class);
         ConfigurationSection dateSection = this.plugin.getConfig().getConfigurationSection("time.gregorian-dates");
         for (SolarTerm term : SolarTerm.values()) {
             String raw = dateSection == null ? null : dateSection.getString(term.key());
             gregorianDates.put(term, parseMonthDay(raw, term.defaultDate()));
         }
 
         Map<Season, SeasonEffectConfig> seasonEffects = new EnumMap<>(Season.class);
         for (Season season : Season.values()) {
             String basePath = "season-effects." + season.key();
             seasonEffects.put(season, new SeasonEffectConfig(
                     this.plugin.getConfig().getDouble(basePath + ".uncovered-crop-growth-multiplier", 1.0D),
                     this.plugin.getConfig().getBoolean(basePath + ".uncovered-crop-stop", false),
                     this.plugin.getConfig().getInt(basePath + ".rain-chance", 20),
                     this.plugin.getConfig().getInt(basePath + ".thunder-chance", 0)
             ));
         }
 
         SeasonWorldRulesConfig seasonWorldRulesConfig = new SeasonWorldRulesConfig(
                 new SeasonWaterCycleConfig(
                         this.plugin.getConfig().getBoolean("season-world-rules.water-cycle.enable", true),
                         this.plugin.getConfig().getLong("season-world-rules.water-cycle.interval-ticks", 40L),
