     private List<String> loadLayout(FileConfiguration guiFile, String path) {
         List<String> layout = guiFile.getStringList(path);
         if (layout.isEmpty()) {
             return List.of();
         }
         return layout.stream()
                 .limit(6)
                 .map(row -> row == null ? "" : row)
                 .toList();
     }
 
     private Map<String, CalendarConfig.LayoutIconConfig> loadLayoutIcons(FileConfiguration guiFile, String path) {
         Map<String, CalendarConfig.LayoutIconConfig> icons = new LinkedHashMap<>();
         ConfigurationSection section = guiFile.getConfigurationSection(path);
         if (section == null) {
             return icons;
         }
         for (String key : section.getKeys(false)) {
             if (key == null || key.isBlank()) {
                 continue;
             }
             String iconPath = path + "." + key;
             CalendarConfig.GuiItemConfig item = loadGuiItem(
                     guiFile,
                     iconPath,
                     guiFile.getBoolean(iconPath + ".enabled", true),
                     -1,
                     loadMaterial(guiFile.getString(iconPath + ".material"), Material.PAPER),
                     loadOptionalMaterial(guiFile.getString(iconPath + ".active-material"), null),
                     loadOptionalMaterial(guiFile.getString(iconPath + ".cold-material"), null),
                     loadOptionalMaterial(guiFile.getString(iconPath + ".hot-material"), null),
                     guiFile.getString(iconPath + ".name", " "),
                     stringList(guiFile, iconPath + ".lore", List.of())
             );
             icons.put(key, new CalendarConfig.LayoutIconConfig(
                     item.enabled(),
                     item.material(),
                     item.activeMaterial(),
                     item.coldMaterial(),
                     item.hotMaterial(),
                     guiFile.getString(iconPath + ".type", "item").trim().toLowerCase(java.util.Locale.ROOT),
                     parseSeason(guiFile.getString(iconPath + ".season")),
                     parseCalendarPage(guiFile.getString(iconPath + ".page")),
+                    guiFile.getString(iconPath + ".content", "default").trim(),
                     item
             ));
         }
         return icons;
     }
 
     private Map<CalendarPage, CalendarConfig.PageConfig> loadPageConfigs(
             FileConfiguration fallbackFile,
             String fallbackTitle,
             int fallbackSize,
             List<String> fallbackLayout,
             Map<String, CalendarConfig.LayoutIconConfig> fallbackIcons,
             Map<String, List<Integer>> fallbackContentSlots
     ) {
         Map<CalendarPage, CalendarConfig.PageConfig> pages = new EnumMap<>(CalendarPage.class);
         for (CalendarPage page : CalendarPage.values()) {
             File pageFile = new File(this.plugin.getDataFolder(), "gui/" + CalendarConfig.navigationKey(page) + ".yml");
             FileConfiguration source = pageFile.exists() ? YamlConfiguration.loadConfiguration(pageFile) : fallbackFile;
             String prefix = source.isConfigurationSection("calendar") ? "calendar" : "menu";
             String title = source.getString(prefix + ".title", fallbackTitle);
             int size = source.getInt(prefix + ".size", rowsToSize(source.getInt(prefix + ".rows", fallbackSize / 9), fallbackSize));
             List<String> layout = loadLayout(source, prefix + ".layout");
             if (layout.isEmpty()) {
                 layout = fallbackLayout;
             }
             Map<String, CalendarConfig.LayoutIconConfig> icons = loadLayoutIcons(source, prefix + ".icons");
             if (icons.isEmpty()) {
                 icons = fallbackIcons;
             }
             Map<String, List<Integer>> contentSlots = new LinkedHashMap<>(fallbackContentSlots);
             ConfigurationSection contentSection = source.getConfigurationSection(prefix + ".content-slots");
             if (contentSection != null) {
                 for (String key : contentSection.getKeys(false)) {
                     contentSlots.put(key, loadIntegerList(source, prefix + ".content-slots." + key, contentSlots.getOrDefault(key, fallbackContentSlots.getOrDefault("default", List.of()))));
                 }
             }
             pages.put(page, new CalendarConfig.PageConfig(title, size, layout, icons, contentSlots));
         }
         return pages;
     }
 
     private Season parseSeason(String raw) {
         if (raw == null || raw.isBlank()) {
             return null;
         }
         try {
             return Season.valueOf(raw.trim().toUpperCase(java.util.Locale.ROOT));
         } catch (IllegalArgumentException ex) {
             this.plugin.getLogger().warning("Invalid gui.yml season '" + raw + "'");
             return null;
         }
     }
 
     private CalendarPage parseCalendarPage(String raw) {
         if (raw == null || raw.isBlank()) {
             return null;
         }
         String normalized = raw.trim().replace('-', '_').toUpperCase(java.util.Locale.ROOT);
         try {
             return CalendarPage.valueOf(normalized);
         } catch (IllegalArgumentException ex) {
             this.plugin.getLogger().warning("Invalid gui.yml page '" + raw + "'");
             return null;
         }
     }
 
     private int rowsToSize(int rows, int fallback) {
         if (rows < 1 || rows > 6) {
             return fallback;
         }
         return rows * 9;
     }
 
     private CalendarConfig.FrameConfig loadFrameConfig(FileConfiguration guiFile) {
         Map<Season, CalendarConfig.FrameSeasonConfig> seasons = new EnumMap<>(Season.class);
         seasons.put(Season.SPRING, loadFrameSeason(guiFile, "spring", Material.BIRCH_PLANKS, Material.PINK_PETALS, Material.GREEN_STAINED_GLASS_PANE));
         seasons.put(Season.SUMMER, loadFrameSeason(guiFile, "summer", Material.JUNGLE_PLANKS, Material.SUNFLOWER, Material.ORANGE_STAINED_GLASS_PANE));
         seasons.put(Season.AUTUMN, loadFrameSeason(guiFile, "autumn", Material.ACACIA_PLANKS, Material.PUMPKIN, Material.BROWN_STAINED_GLASS_PANE));
         seasons.put(Season.WINTER, loadFrameSeason(guiFile, "winter", Material.SPRUCE_PLANKS, Material.SNOW_BLOCK, Material.BLUE_STAINED_GLASS_PANE));
         return new CalendarConfig.FrameConfig(
                 guiFile.getBoolean("calendar.season-frame.enabled", guiFile.getBoolean("calendar.season-frame", true)),
                 loadIntegerList(guiFile, "calendar.season-frame.frame-slots", List.of(0, 1, 2, 3, 5, 6, 7, 8, 9, 17, 18, 26, 27, 35, 36, 44, 47, 53)),
                 loadIntegerList(guiFile, "calendar.season-frame.corner-slots", List.of(0, 8, 36, 44)),
                 loadIntegerList(guiFile, "calendar.season-frame.accent-slots", List.of(10, 11, 12, 14, 15, 16, 28, 29, 30, 32, 33, 34)),
                 seasons
         );
     }
 
     private CalendarConfig.FrameSeasonConfig loadFrameSeason(FileConfiguration guiFile, String season, Material frame, Material corner, Material accent) {
         String path = "calendar.season-frame.seasons." + season;
         return new CalendarConfig.FrameSeasonConfig(
                 loadMaterial(guiFile.getString(path + ".frame-material"), frame),
                 loadMaterial(guiFile.getString(path + ".corner-material"), corner),
                 loadMaterial(guiFile.getString(path + ".accent-material"), accent)
         );
     }
 
     private CalendarConfig.GuiItemConfig loadGuiItem(FileConfiguration guiFile, String path, boolean defaultEnabled, int defaultSlot, Material defaultMaterial, Material defaultActiveMaterial, Material defaultColdMaterial, Material defaultHotMaterial, String defaultName, List<String> defaultLore) {
         return new CalendarConfig.GuiItemConfig(
                 guiFile.getBoolean(path + ".enabled", defaultEnabled),
                 normalizeSlot(guiFile.getInt(path + ".slot", defaultSlot), defaultSlot),
                 loadMaterial(guiFile.getString(path + ".material"), defaultMaterial),
                 loadOptionalMaterial(guiFile.getString(path + ".active-material"), defaultActiveMaterial),
                 loadOptionalMaterial(guiFile.getString(path + ".cold-material"), defaultColdMaterial),
                 loadOptionalMaterial(guiFile.getString(path + ".hot-material"), defaultHotMaterial),
                 guiFile.getString(path + ".name", defaultName),
                 stringList(guiFile, path + ".lore", defaultLore)
         );
     }
 
     private List<Integer> loadIntegerList(FileConfiguration guiFile, String path, List<Integer> defaults) {
         List<Integer> values = guiFile.getIntegerList(path);
         if (values.isEmpty()) {
             return defaults;
         }
         return values.stream()
                 .filter(value -> value >= 0 && value < 54)
                 .distinct()
                 .toList();
     }
 
     private List<String> stringList(FileConfiguration guiFile, String path, List<String> defaults) {
         List<String> values = guiFile.getStringList(path);
         return values.isEmpty() ? defaults : values;
     }
 
     private int normalizeSlot(int value, int fallback) {
         if (value < 0 || value >= 54) {
             return fallback;
         }
         return value;
     }
 
     private Material loadMaterial(String raw, Material fallback) {
         Material material = loadOptionalMaterial(raw, fallback);
         return material == null ? fallback : material;
     }
 
     private Material loadOptionalMaterial(String raw, Material fallback) {
         if (raw == null || raw.isBlank()) {
             return fallback;
         }
         Material material = Material.matchMaterial(raw.trim());
         if (material == null) {
             this.plugin.getLogger().warning("Invalid gui.yml material '" + raw + "', fallback to " + (fallback == null ? "empty" : fallback.name()));
             return fallback;
         }
         return material;
     }
 
